#include <vector>
#include <unordered_map>
#include <set>
#include <algorithm>

using namespace std;

class UnionFind {
private:
    vector<long long> parent;
    vector<long long> rank;
public:
    UnionFind(long long size) {
        parent.resize(size + 1);
        rank.resize(size + 1, 0);
        for (long long i = 1; i <= size; ++i) {
            parent[i] = i;
        }
    }

    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(long long x, long long y) {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX != rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
        }
    }
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    UnionFind uf(c);
    for (const auto& conn : connections) {
        uf.unite(conn[0], conn[1]);
    }

    unordered_map<long long, set<long long>> componentMinNodes;
    vector<bool> online(c + 1, true);

    for (long long i = 1; i <= c; ++i) {
        long long root = uf.find(i);
        componentMinNodes[root].insert(i);
    }

    vector<long long> result;
    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            long long root = uf.find(x);
            if (online[x]) {
                result.push_back(x);
            } else {
                auto& nodes = componentMinNodes[root];
                auto it = nodes.lower_bound(1);
                while (it != nodes.end() && !online[*it]) {
                    ++it;
                }
                if (it != nodes.end()) {
                    result.push_back(*it);
                } else {
                    result.push_back(-1);
                }
            }
        } else if (type == 2) {
            online[x] = false;
        }
    }
    return result;
}

