use std::collections::{HashMap, BTreeSet};

struct UnionFind {
    parent: Vec<i64>,
    rank: Vec<i64>,
}

impl UnionFind {
    fn new(size: i64) -> Self {
        let mut parent = vec![0; (size + 1) as usize];
        let rank = vec![0; (size + 1) as usize];
        for i in 1..=size {
            parent[i as usize] = i;
        }
        UnionFind { parent, rank }
    }

    fn find(&mut self, x: i64) -> i64 {
        if self.parent[x as usize] != x {
            self.parent[x as usize] = self.find(self.parent[x as usize]);
        }
        self.parent[x as usize]
    }

    fn unite(&mut self, x: i64, y: i64) {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x != root_y {
            if self.rank[root_x as usize] < self.rank[root_y as usize] {
                self.parent[root_x as usize] = root_y;
            } else if self.rank[root_x as usize] > self.rank[root_y as usize] {
                self.parent[root_y as usize] = root_x;
            } else {
                self.parent[root_y as usize] = root_x;
                self.rank[root_x as usize] += 1;
            }
        }
    }
}

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut uf = UnionFind::new(c);
    for conn in connections {
        uf.unite(conn[0], conn[1]);
    }

    let mut component_min_nodes: HashMap<i64, BTreeSet<i64>> = HashMap::new();
    let mut online = vec![true; (c + 1) as usize];

    for i in 1..=c {
        let root = uf.find(i);
        component_min_nodes.entry(root).or_default().insert(i);
    }

    let mut result = Vec::new();
    for query in queries {
        let query_type = query[0];
        let x = query[1];
        if query_type == 1 {
            let root = uf.find(x);
            if online[x as usize] {
                result.push(x);
            } else {
                let nodes = component_min_nodes.get(&root).unwrap();
                let mut answer = -1;
                for &node in nodes {
                    if online[node as usize] {
                        answer = node;
                        break;
                    }
                }
                result.push(answer);
            }
        } else if query_type == 2 {
            online[x as usize] = false;
        }
    }
    result
}
